import{_ as a,o as i,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Introducing Scheduled Dashboard Email Reports","description":"","frontmatter":{"title":"Introducing Scheduled Dashboard Email Reports","slug":"introducing-scheduled-dashboard-email-reports"},"headers":[],"relativePath":"account-hub/introducing-scheduled-dashboard-email-reports.md","filePath":"account-hub/introducing-scheduled-dashboard-email-reports.md"}'),r={name:"account-hub/introducing-scheduled-dashboard-email-reports.md"};function s(n,e,l,d,c,u){return i(),t("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch is excited to announce a highly requested feature for Branch users: <strong>Scheduled Dashboard Email Reports</strong>!</p><p>This new functionality allows you to configure your analytics reports to be delivered directly to your and your colleagues&#39; inboxes, eliminating the need to log into Branch to access your essential data. This streamlines your workflow and ensures you have timely access to the performance insights you need.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>This feature is integrated directly into our existing Saved Views functionality, making it easy to manage your scheduled reports.</p><p>You can choose from various delivery cadences, including daily, weekly, or monthly, and the reports will include a CSV download of your saved table configuration.</p><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><p>This highly anticipated feature offers significant benefits for performance marketers using Branch. By enabling scheduled delivery of your analytics reports directly to your and your colleagues&#39; inboxes, you&#39;ll save valuable time currently spent logging into Branch to pull data.</p><p>Furthermore, consistent and automated delivery of key performance indicators ensures that all relevant stakeholders have immediate access to up-to-date insights, fostering better-informed decisions and more agile responses to market changes.</p><p>This feature ultimately empowers you to stay on top of your campaign performance with minimal effort, allowing you to focus on what matters most.</p><h2 id="availability" tabindex="-1">Availability <a class="header-anchor" href="#availability" aria-label="Permalink to &quot;Availability&quot;">​</a></h2><p>At launch, this feature will be available on the following Branch Dashboard pages:</p><ul><li>Overview → Sources</li><li>Ads Analytics → Unified</li><li>Ads Analytics → Activity</li><li>Household → Analytics</li><li>SEO → Analytics</li><li>Email → Activity</li><li>QR Codes → Analytics</li></ul><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h2><p>To learn more about this feature, including detailed steps on how to use it in the Branch Dashboard, please see our <a href="./scheduled-dashboard-email-reports.html">guide</a>.</p>',15)])])}const p=a(r,[["render",s]]);export{m as __pageData,p as default};
